def get_input(prompt, default=None, exit_msg='bye!'):
    try:
        response = six.moves.input(prompt)
    except (KeyboardInterrupt, EOFError):
        print()
        print(exit_msg)
        exit()
    try:
        return int(response)
    except ValueError:
        if response.strip() == "" and default is not None:
            return default
        else:
            return response

